svg.script:
(async () => {
  const status = document.getElementById("status");
  try {
    if (!("serviceWorker" in navigator)) {
      throw new Error("当前浏览器不支持 Service Worker");
    }
    const registration = await navigator.serviceWorker.register("./coi-serviceworker.js");
    const worker = registration.installing || registration.waiting || registration.active;
    if (!worker) throw new Error("无法启动隔离服务");
    if (worker.state !== "activated") {
      await new Promise((resolve, reject) => {
        worker.addEventListener("statechange", () => {
          if (worker.state === "activated") resolve();
          if (worker.state === "redundant") reject(new Error("隔离服务安装失败"));
        });
      });
    }
    status.textContent = "环境准备完成，正在打开 Mainly.C…";
    location.replace(new URL("index.html", location.href).href);
  } catch (error) {
    status.setAttribute("fill", "#fda4af");
    status.textContent = error instanceof Error ? error.message : String(error);
  }
})();
